const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
return { json: { token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true } };

// Shape the market-intelligence dashboard response.
// - active_signals: currently-influencing signals (not decayed, not needs_review)
// - by_type: counts by signal_type
// - by_vertical: counts by affected vertical
// - ingestion_stats: per-source poll volume + processed rate
// - routing_impact: outreach multipliers applied + decision counts
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const signals = allOf('Active Signals');
const ingest  = allOf('Ingestion Stats 7d');
const routing = allOf('Routing Log 7d');

// By signal_type
const byType = {};
signals.forEach(function (s) {
  if (!s || !s.signal_type) return;
  byType[s.signal_type] = (byType[s.signal_type] || 0) + 1;
});

// By vertical (affected_verticals is an array of {vertical, impact, outreach_multiplier, ...})
const byVertical = {};
signals.forEach(function (s) {
  const av = Array.isArray(s.affected_verticals) ? s.affected_verticals : [];
  av.forEach(function (v) {
    if (!v || !v.vertical) return;
    if (!byVertical[v.vertical]) byVertical[v.vertical] = { count: 0, top_multiplier: 1.0 };
    byVertical[v.vertical].count++;
    const m = Number(v.outreach_multiplier) || 1.0;
    if (m > byVertical[v.vertical].top_multiplier) byVertical[v.vertical].top_multiplier = m;
  });
});

// By region
const byRegion = {};
signals.forEach(function (s) {
  const regs = Array.isArray(s.affected_regions) ? s.affected_regions : [];
  regs.forEach(function (r) {
    if (!r) return;
    const key = String(r).slice(0, 80);
    byRegion[key] = (byRegion[key] || 0) + 1;
  });
});

// Per-source ingestion stats
const bySource = {};
ingest.forEach(function (r) {
  if (!r || !r.source) return;
  if (!bySource[r.source]) bySource[r.source] = { total: 0, processed: 0, needs_review: 0 };
  bySource[r.source].total++;
  if (r.processed)    bySource[r.source].processed++;
  if (r.needs_review) bySource[r.source].needs_review++;
});
Object.keys(bySource).forEach(function (k) {
  const s = bySource[k];
  s.processed_rate_pct = s.total > 0 ? Math.round((s.processed / s.total) * 100) : null;
});

// Routing impact
const routingByDecision = {};
let outreachSends7d = 0;
routing.forEach(function (r) {
  if (!r) return;
  const k = r.decision_type || 'unknown';
  routingByDecision[k] = (routingByDecision[k] || 0) + 1;
  outreachSends7d++;
});

// Recent activity timeline (top 20 signals by recency)
const recent = signals.slice(0, 20).map(function (s) {
  return {
    id: s.id,
    headline: s.headline,
    signal_type: s.signal_type,
    confidence: s.confidence,
    age_hours: s.age_hours ? Math.round(s.age_hours) : null,
    decay_time_days: s.decay_time_days,
    affected_verticals: s.affected_verticals,
    affected_regions: s.affected_regions,
    messaging_angle: s.messaging_angle,
    source_url: s.source_url
  };
});

return { json: { ok: true, data: {
  totals: {
    active_signals: signals.length,
    sources_polled_7d: Object.keys(bySource).length,
    signals_ingested_7d: ingest.length,
    routing_decisions_7d: routing.length
  },
  by_type: byType,
  by_vertical: byVertical,
  by_region: byRegion,
  by_source: bySource,
  routing_by_decision: routingByDecision,
  recent_signals: recent
} } };
